import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface Stay {
  id: string;
  hotelName: string;
  brand: string;
  date: string; // ISO date string YYYY-MM-DD
  notes?: string;
  createdAt: number;
}

export interface BrandGroup {
  brand: string;
  count: number;
  stays: Stay[];
}

export type ViewMode = 'dashboard' | 'portfolio' | 'share';

export interface StatSummary {
  totalStays: number;
  uniqueBrands: number;
  topBrand: string;
  thisYearStays: number;
}

import { Stay } from '../types';

// Key for localStorage
const STORAGE_KEY = 'stayfolio_data';

// Initial dummy data to populate the view if empty
const INITIAL_DATA: Stay[] = [
  { id: '1', hotelName: 'Grand Hyatt Tokyo', brand: 'Hyatt', date: '2023-11-15', createdAt: 1700000000000 },
  { id: '2', hotelName: 'Marriott Marquis NY', brand: 'Marriott', date: '2023-12-01', createdAt: 1700000000000 },
  { id: '3', hotelName: 'Hyatt Regency London', brand: 'Hyatt', date: '2024-01-20', createdAt: 1700000000000 },
  { id: '4', hotelName: 'Hilton Garden Inn', brand: 'Hilton', date: '2024-02-14', createdAt: 1700000000000 },
  { id: '5', hotelName: 'Andaz 5th Avenue', brand: 'Hyatt', date: '2024-03-10', createdAt: 1700000000000 },
  { id: '6', hotelName: 'W Barcelona', brand: 'Marriott', date: '2024-05-22', createdAt: 1700000000000 },
];

export const getStays = (): Stay[] => {
  const data = localStorage.getItem(STORAGE_KEY);
  if (!data) {
    // Initialize with dummy data for better first-time UX
    localStorage.setItem(STORAGE_KEY, JSON.stringify(INITIAL_DATA));
    return INITIAL_DATA;
  }
  try {
    return JSON.parse(data);
  } catch (e) {
    return [];
  }
};

export const addStay = (stay: Omit<Stay, 'id' | 'createdAt'>): Stay => {
  const currentStays = getStays();
  const newStay: Stay = {
    ...stay,
    id: crypto.randomUUID(),
    createdAt: Date.now(),
  };
  const updatedStays = [newStay, ...currentStays];
  localStorage.setItem(STORAGE_KEY, JSON.stringify(updatedStays));
  return newStay;
};

export const deleteStay = (id: string): void => {
  const currentStays = getStays();
  const updatedStays = currentStays.filter(s => s.id !== id);
  localStorage.setItem(STORAGE_KEY, JSON.stringify(updatedStays));
};

import { GoogleGenAI } from "@google/genai";
import { Stay } from "../types";

const createPrompt = (stays: Stay[]) => {
  // Take the last 5 stays or interesting summary stats to keep context small
  const recentStays = stays.slice(0, 10).map(s => `${s.hotelName} (${s.brand}) in ${s.date}`).join(', ');
  const total = stays.length;
  const brands = new Set(stays.map(s => s.brand)).size;

  return `
    I am a travel enthusiast tracking my hotel stays.
    Here is a summary of my portfolio:
    Total Stays: ${total}
    Unique Brands: ${brands}
    Recent Stays: ${recentStays}

    Write a short, engaging, emoji-rich Instagram caption (under 50 words) that celebrates my travel journey and brand loyalty. 
    Focus on the joy of exploring new hotels. 
    Do not include hashtags.
  `;
};

export const generateSocialCaption = async (stays: Stay[]): Promise<string> => {
  if (!process.env.API_KEY) {
    return "Please configure your API_KEY to generate AI captions.";
  }

  try {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: createPrompt(stays),
    });

    return response.text || "Could not generate caption.";
  } catch (error) {
    console.error("AI Generation Error:", error);
    return "Oops! Had a little trouble connecting to the travel muse. Try again later.";
  }
};

import React, { useState } from 'react';
import { Plus, X } from 'lucide-react';
import { Stay } from '../types';

interface StayFormProps {
  onAdd: (stay: Omit<Stay, 'id' | 'createdAt'>) => void;
  onClose: () => void;
}

const POPULAR_BRANDS = ['Marriott', 'Hyatt', 'Hilton', 'IHG', 'Accor', 'Four Seasons', 'Best Western', 'Wyndham', 'Choice', 'Radisson'];

export const StayForm: React.FC<StayFormProps> = ({ onAdd, onClose }) => {
  const [hotelName, setHotelName] = useState('');
  const [brand, setBrand] = useState('');
  const [date, setDate] = useState(new Date().toISOString().split('T')[0]);
  const [customBrand, setCustomBrand] = useState(false);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (hotelName && brand && date) {
      onAdd({ hotelName, brand, date });
      onClose();
    }
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50 backdrop-blur-sm p-4">
      <div className="bg-white rounded-2xl shadow-xl w-full max-w-md overflow-hidden animate-fade-in-up">
        <div className="bg-indigo-600 p-6 text-white flex justify-between items-center">
          <h2 className="text-xl font-bold">Add New Stay</h2>
          <button onClick={onClose} className="hover:bg-indigo-700 p-1 rounded-full transition-colors">
            <X size={20} />
          </button>
        </div>

        <form onSubmit={handleSubmit} className="p-6 space-y-6">
          <div className="space-y-2">
            <label className="block text-sm font-medium text-slate-700">Hotel Name</label>
            <input
              type="text"
              value={hotelName}
              onChange={(e) => setHotelName(e.target.value)}
              placeholder="e.g. Grand Hyatt Tokyo"
              className="w-full px-4 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 outline-none transition-all"
              required
            />
          </div>

          <div className="space-y-2">
            <label className="block text-sm font-medium text-slate-700">Brand</label>
            {!customBrand ? (
              <div className="grid grid-cols-2 gap-2">
                 <select 
                    value={brand} 
                    onChange={(e) => {
                        if (e.target.value === 'Other') {
                            setCustomBrand(true);
                            setBrand('');
                        } else {
                            setBrand(e.target.value);
                        }
                    }}
                    className="col-span-2 w-full px-4 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none"
                 >
                    <option value="" disabled>Select a Brand</option>
                    {POPULAR_BRANDS.map(b => <option key={b} value={b}>{b}</option>)}
                    <option value="Other">Other (Type custom)</option>
                 </select>
              </div>
            ) : (
              <div className="flex gap-2">
                <input
                  type="text"
                  value={brand}
                  onChange={(e) => setBrand(e.target.value)}
                  placeholder="Enter Brand Name"
                  className="w-full px-4 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none"
                  autoFocus
                  required
                />
                <button 
                    type="button" 
                    onClick={() => setCustomBrand(false)}
                    className="text-xs text-slate-500 underline whitespace-nowrap"
                >
                    Back to list
                </button>
              </div>
            )}
          </div>

          <div className="space-y-2">
            <label className="block text-sm font-medium text-slate-700">Check-in Date</label>
            <input
              type="date"
              value={date}
              onChange={(e) => setDate(e.target.value)}
              className="w-full px-4 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none"
              required
            />
          </div>

          <div className="pt-4">
            <button
              type="submit"
              className="w-full bg-indigo-600 text-white font-semibold py-3 rounded-xl hover:bg-indigo-700 transition-all shadow-lg shadow-indigo-200 flex items-center justify-center gap-2"
            >
              <Plus size={20} />
              Add to Portfolio
            </button>
          </div>
        </form>
      </div>
    </div>
  );
};

import React, { useMemo } from 'react';
import { BrandGroup, Stay } from '../types';
import { Building2, Calendar, MapPin } from 'lucide-react';

interface BrandPortfolioProps {
  stays: Stay[];
}

export const BrandPortfolio: React.FC<BrandPortfolioProps> = ({ stays }) => {
  const brandGroups: BrandGroup[] = useMemo(() => {
    const groups: Record<string, Stay[]> = {};
    stays.forEach(stay => {
      const b = stay.brand || 'Unbranded';
      if (!groups[b]) groups[b] = [];
      groups[b].push(stay);
    });

    return Object.entries(groups)
      .map(([brand, stays]) => ({
        brand,
        count: stays.length,
        stays: stays.sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime())
      }))
      .sort((a, b) => b.count - a.count);
  }, [stays]);

  const getBrandColor = (brand: string) => {
    // Simple hashing for consistent colors
    const colors = [
      'bg-blue-500', 'bg-indigo-500', 'bg-purple-500', 
      'bg-rose-500', 'bg-amber-500', 'bg-teal-500', 'bg-cyan-500'
    ];
    let hash = 0;
    for (let i = 0; i < brand.length; i++) {
      hash = brand.charCodeAt(i) + ((hash << 5) - hash);
    }
    return colors[Math.abs(hash) % colors.length];
  };

  return (
    <div className="space-y-6 pb-20">
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {brandGroups.map((group) => (
          <div key={group.brand} className="bg-white rounded-2xl shadow-sm border border-slate-100 overflow-hidden hover:shadow-md transition-shadow">
            <div className={`p-4 ${getBrandColor(group.brand)} text-white flex justify-between items-center`}>
              <div className="flex items-center gap-2">
                <Building2 size={20} className="opacity-90" />
                <h3 className="font-bold text-lg">{group.brand}</h3>
              </div>
              <span className="bg-white/20 px-3 py-1 rounded-full text-xs font-medium backdrop-blur-sm">
                {group.count} {group.count === 1 ? 'Stay' : 'Stays'}
              </span>
            </div>

            <div className="p-4 max-h-60 overflow-y-auto space-y-3 custom-scrollbar">
              {group.stays.map(stay => (
                <div key={stay.id} className="flex items-start gap-3 p-3 rounded-lg bg-slate-50 hover:bg-slate-100 transition-colors">
                   <div className="mt-1 min-w-[4px] h-10 rounded-full bg-slate-300"></div>
                   <div>
                      <p className="font-medium text-slate-800 text-sm leading-tight">{stay.hotelName}</p>
                      <div className="flex items-center gap-1 text-xs text-slate-500 mt-1">
                        <Calendar size={12} />
                        <span>{stay.date}</span>
                      </div>
                   </div>
                </div>
              ))}
            </div>

            <div className="bg-slate-50 p-3 text-center border-t border-slate-100">
               <span className="text-xs font-semibold text-slate-400 uppercase tracking-wider">
                  {((group.count / stays.length) * 100).toFixed(0)}% of your portfolio
               </span>
            </div>
          </div>
        ))}
      </div>

      {stays.length === 0 && (
        <div className="text-center py-20 bg-white rounded-3xl border-2 border-dashed border-slate-200">
          <Building2 size={48} className="mx-auto text-slate-300 mb-4" />
          <h3 className="text-lg font-medium text-slate-600">No brands collected yet</h3>
          <p className="text-slate-400 text-sm">Add your first hotel stay to see your portfolio grow.</p>
        </div>
      )}
    </div>
  );
};

import React, { useState } from 'react';
import { Stay, StatSummary } from '../types';
import { Share2, Sparkles, Copy, Check } from 'lucide-react';
import { generateSocialCaption } from '../services/ai';
import { PieChart, Pie, Cell, Tooltip, ResponsiveContainer } from 'recharts';

interface ShareViewProps {
  stays: Stay[];
  summary: StatSummary;
}

export const ShareView: React.FC<ShareViewProps> = ({ stays, summary }) => {
  const [caption, setCaption] = useState<string | null>(null);
  const [loading, setLoading] = useState(false);
  const [copied, setCopied] = useState(false);

  const handleGenerateCaption = async () => {
    setLoading(true);
    const text = await generateSocialCaption(stays);
    setCaption(text);
    setLoading(false);
  };

  const copyToClipboard = () => {
    if (caption) {
      navigator.clipboard.writeText(caption);
      setCopied(true);
      setTimeout(() => setCopied(false), 2000);
    }
  };

  // Prepare data for chart
  const brandData = React.useMemo(() => {
    const counts: Record<string, number> = {};
    stays.forEach(s => counts[s.brand] = (counts[s.brand] || 0) + 1);
    return Object.entries(counts)
      .map(([name, value]) => ({ name, value }))
      .sort((a, b) => b.value - a.value)
      .slice(0, 5); // Top 5
  }, [stays]);

  const COLORS = ['#6366f1', '#8b5cf6', '#ec4899', '#f59e0b', '#10b981'];

  return (
    <div className="max-w-xl mx-auto space-y-8 pb-20">

      {/* The Visual Card (Simulates an IG Story or Post) */}
      <div className="bg-gradient-to-br from-indigo-600 to-purple-700 rounded-3xl p-8 text-white shadow-2xl relative overflow-hidden">
        {/* Background Patterns */}
        <div className="absolute top-0 right-0 w-64 h-64 bg-white/10 rounded-full blur-3xl -mr-16 -mt-16 pointer-events-none"></div>
        <div className="absolute bottom-0 left-0 w-48 h-48 bg-black/10 rounded-full blur-2xl -ml-10 -mb-10 pointer-events-none"></div>

        <div className="relative z-10 text-center space-y-6">
          <div className="inline-block px-4 py-1 rounded-full bg-white/20 backdrop-blur-md text-xs font-semibold tracking-wider uppercase border border-white/10">
            Travel Portfolio
          </div>

          <div className="py-4">
             <h1 className="text-6xl font-black tracking-tighter drop-shadow-sm">
                {summary.totalStays}
             </h1>
             <p className="text-indigo-100 text-lg font-medium">Hotel Stays Collected</p>
          </div>

          <div className="grid grid-cols-2 gap-4 bg-white/10 rounded-2xl p-4 backdrop-blur-sm border border-white/5">
            <div className="text-center">
              <span className="block text-2xl font-bold">{summary.uniqueBrands}</span>
              <span className="text-xs text-indigo-200 uppercase tracking-wide">Unique Brands</span>
            </div>
            <div className="text-center border-l border-white/10">
              <span className="block text-2xl font-bold">{summary.topBrand || '-'}</span>
              <span className="text-xs text-indigo-200 uppercase tracking-wide">Top Loyalty</span>
            </div>
          </div>

          <div className="h-48 w-full">
            <ResponsiveContainer width="100%" height="100%">
                <PieChart>
                    <Pie
                        data={brandData}
                        cx="50%"
                        cy="50%"
                        innerRadius={40}
                        outerRadius={70}
                        paddingAngle={5}
                        dataKey="value"
                    >
                        {brandData.map((entry, index) => (
                            <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} stroke="rgba(255,255,255,0.2)" />
                        ))}
                    </Pie>
                    <Tooltip 
                        contentStyle={{ borderRadius: '12px', border: 'none', boxShadow: '0 4px 6px -1px rgba(0, 0, 0, 0.1)' }}
                        itemStyle={{ color: '#4f46e5', fontWeight: 'bold' }}
                    />
                </PieChart>
            </ResponsiveContainer>
          </div>

          <div className="text-xs text-indigo-200 font-mono pt-4 opacity-70">
            Generated by StayFolio
          </div>
        </div>
      </div>

      {/* AI Controls */}
      <div className="bg-white rounded-2xl p-6 shadow-sm border border-slate-100">
        <div className="flex items-center gap-3 mb-4">
            <div className="p-2 bg-gradient-to-r from-pink-500 to-violet-500 rounded-lg text-white">
                <Sparkles size={20} />
            </div>
            <h3 className="font-bold text-slate-800">AI Caption Generator</h3>
        </div>

        <p className="text-slate-500 text-sm mb-6">
            Get a fun, AI-generated caption for this portfolio to post on Instagram or Twitter.
        </p>

        {!caption ? (
             <button 
                onClick={handleGenerateCaption}
                disabled={loading}
                className="w-full py-3 bg-slate-900 text-white rounded-xl font-medium hover:bg-slate-800 transition-colors disabled:opacity-50 flex justify-center items-center gap-2"
             >
                {loading ? (
                    <>
                        <span className="animate-spin rounded-full h-4 w-4 border-2 border-white border-t-transparent"></span>
                        Thinking...
                    </>
                ) : (
                    <>Generate Caption</>
                )}
             </button>
        ) : (
            <div className="space-y-4 animate-fade-in">
                <div className="bg-slate-50 p-4 rounded-xl border border-slate-200 text-slate-700 italic text-sm leading-relaxed">
                    "{caption}"
                </div>
                <div className="flex gap-2">
                    <button 
                        onClick={copyToClipboard}
                        className={`flex-1 py-2 rounded-lg font-medium text-sm flex items-center justify-center gap-2 transition-all ${
                            copied ? 'bg-green-100 text-green-700' : 'bg-slate-100 text-slate-700 hover:bg-slate-200'
                        }`}
                    >
                        {copied ? <Check size={16} /> : <Copy size={16} />}
                        {copied ? 'Copied!' : 'Copy Text'}
                    </button>
                    <button 
                        onClick={() => setCaption(null)}
                        className="px-4 py-2 bg-white border border-slate-200 text-slate-600 rounded-lg text-sm hover:bg-slate-50 font-medium"
                    >
                        Regenerate
                    </button>
                </div>
            </div>
        )}
      </div>

      <div className="text-center">
         <button className="text-indigo-600 font-medium text-sm hover:text-indigo-800 flex items-center justify-center gap-2 mx-auto">
            <Share2 size={16} />
            Share Image (Simulated)
         </button>
         <p className="text-xs text-slate-400 mt-2">
            In a real app, this would trigger the native share sheet or download the card as PNG.
         </p>
      </div>

    </div>
  );
};

import React, { useState, useEffect, useMemo } from 'react';
import { LayoutDashboard, Briefcase, Share2, Plus, Hotel, Trash2 } from 'lucide-react';
import { Stay, ViewMode, StatSummary } from './types';
import { getStays, addStay, deleteStay } from './services/storage';
import { StayForm } from './components/StayForm';
import { BrandPortfolio } from './components/BrandPortfolio';
import { ShareView } from './components/ShareView';

const App: React.FC = () => {
  const [stays, setStays] = useState<Stay[]>([]);
  const [view, setView] = useState<ViewMode>('dashboard');
  const [isFormOpen, setIsFormOpen] = useState(false);

  useEffect(() => {
    setStays(getStays());
  }, []);

  const handleAddStay = (stayData: Omit<Stay, 'id' | 'createdAt'>) => {
    const newStay = addStay(stayData);
    setStays(prev => [newStay, ...prev]);
  };

  const handleDeleteStay = (id: string) => {
    deleteStay(id);
    setStays(prev => prev.filter(s => s.id !== id));
  };

  const stats: StatSummary = useMemo(() => {
    const uniqueBrands = new Set(stays.map(s => s.brand));
    const brandCounts: Record<string, number> = {};
    stays.forEach(s => brandCounts[s.brand] = (brandCounts[s.brand] || 0) + 1);

    const topBrand = Object.entries(brandCounts).sort((a, b) => b.1 - a.1)[0]?.[0] || '';

    return {
      totalStays: stays.length,
      uniqueBrands: uniqueBrands.size,
      topBrand,
      thisYearStays: stays.filter(s => new Date(s.date).getFullYear() === new Date().getFullYear()).length
    };
  }, [stays]);

  return (
    <div className="min-h-screen pb-20 md:pb-0">
      {/* Header */}
      <header className="bg-white sticky top-0 z-30 border-b border-slate-200">
        <div className="max-w-3xl mx-auto px-4 h-16 flex items-center justify-between">
          <div className="flex items-center gap-2 text-indigo-600">
            <div className="bg-indigo-600 p-1.5 rounded-lg text-white">
                <Hotel size={20} />
            </div>
            <h1 className="font-bold text-xl tracking-tight text-slate-900">StayFolio</h1>
          </div>
          <div className="text-xs font-medium text-slate-500 bg-slate-100 px-3 py-1 rounded-full">
            {stats.totalStays} Stays Tracked
          </div>
        </div>
      </header>

      {/* Main Content */}
      <main className="max-w-3xl mx-auto px-4 py-6">

        {/* Dashboard View */}
        {view === 'dashboard' && (
          <div className="space-y-6">
            <div className="grid grid-cols-3 gap-4">
                <div className="bg-white p-4 rounded-2xl shadow-sm border border-slate-100 text-center">
                    <span className="block text-3xl font-bold text-slate-800">{stats.uniqueBrands}</span>
                    <span className="text-xs text-slate-500 font-medium uppercase tracking-wide">Brands</span>
                </div>
                <div className="bg-white p-4 rounded-2xl shadow-sm border border-slate-100 text-center">
                    <span className="block text-3xl font-bold text-indigo-600">{stats.thisYearStays}</span>
                    <span className="text-xs text-slate-500 font-medium uppercase tracking-wide">This Year</span>
                </div>
                <div className="bg-white p-4 rounded-2xl shadow-sm border border-slate-100 text-center">
                    <span className="block text-3xl font-bold text-slate-800">{stats.topBrand ? stats.topBrand.slice(0, 8) : '-'}</span>
                    <span className="text-xs text-slate-500 font-medium uppercase tracking-wide">Top Loyalty</span>
                </div>
            </div>

            <div className="flex justify-between items-end">
                <h2 className="text-lg font-bold text-slate-800">Recent Activity</h2>
                <button 
                    onClick={() => setIsFormOpen(true)}
                    className="text-indigo-600 text-sm font-medium hover:bg-indigo-50 px-3 py-1 rounded-lg transition-colors flex items-center gap-1"
                >
                    <Plus size={16} /> Add Stay
                </button>
            </div>

            <div className="space-y-3 pb-20">
                {stays.length === 0 ? (
                     <div className="text-center py-12 bg-white rounded-2xl border-2 border-dashed border-slate-200">
                        <p className="text-slate-400">No stays yet. Start tracking your journey!</p>
                        <button onClick={() => setIsFormOpen(true)} className="mt-4 px-6 py-2 bg-indigo-600 text-white rounded-lg text-sm font-medium">Add First Stay</button>
                    </div>
                ) : (
                    stays.map(stay => (
                        <div key={stay.id} className="bg-white p-4 rounded-xl shadow-sm border border-slate-100 flex justify-between items-center group">
                            <div className="flex items-center gap-4">
                                <div className="w-12 h-12 rounded-full bg-indigo-50 flex items-center justify-center text-indigo-600 font-bold text-lg">
                                    {stay.brand.charAt(0)}
                                </div>
                                <div>
                                    <h3 className="font-semibold text-slate-800">{stay.hotelName}</h3>
                                    <div className="flex items-center gap-2 text-sm text-slate-500">
                                        <span className="font-medium text-slate-600">{stay.brand}</span>
                                        <span>•</span>
                                        <span>{stay.date}</span>
                                    </div>
                                </div>
                            </div>
                            <button 
                                onClick={() => handleDeleteStay(stay.id)}
                                className="text-slate-300 hover:text-red-500 p-2 opacity-0 group-hover:opacity-100 transition-all"
                                title="Delete"
                            >
                                <Trash2 size={18} />
                            </button>
                        </div>
                    ))
                )}
