// Key for localStorage
const STORAGE_KEY = 'stayfolio_data';

// Initial dummy data to populate the view if empty
const INITIAL_DATA: Stay[] = [
  { id: '1', hotelName: 'Grand Hyatt Tokyo', brand: 'World of Hyatt', country: 'Japan', date: '2023-11-15', createdAt: 1700000000000 },
  { id: '2', hotelName: 'Marriott Marquis NY', brand: 'Marriott Bonvoy', country: 'USA', date: '2023-12-01', createdAt: 1700000000000 },
  { id: '3', hotelName: 'Hyatt Regency London', brand: 'World of Hyatt', country: 'UK', date: '2024-01-20', createdAt: 1700000000000 },
  { id: '4', hotelName: 'Hilton Garden Inn', brand: 'Hilton Honors', country: 'UK', date: '2024-02-14', createdAt: 1700000000000 },
  { id: '5', hotelName: 'Andaz 5th Avenue', brand: 'World of Hyatt', country: 'USA', date: '2024-03-10', createdAt: 1700000000000 },
  { id: '6', hotelName: 'W Barcelona', brand: 'Marriott Bonvoy', country: 'Spain', date: '2024-05-22', createdAt: 1700000000000 },
  { id: '7', hotelName: 'InterContinental Paris', brand: 'IHG One Rewards', country: 'France', date: '2024-06-15', createdAt: 1700000000000 },
];

export const getStays = (): Stay[] => {
  const data = localStorage.getItem(STORAGE_KEY);
  if (!data) {
    // Initialize with dummy data for better first-time UX
    localStorage.setItem(STORAGE_KEY, JSON.stringify(INITIAL_DATA));
    return INITIAL_DATA;
  }
  try {
    const parsed = JSON.parse(data);
    // Migration for old data without country
    return parsed.map((s: any) => ({
        ...s,
        country: s.country || 'Unknown' 
    }));
  } catch (e) {
    return [];
  }
};

export const addStay = (stay: Omit<Stay, 'id' | 'createdAt'>): Stay => {
  const currentStays = getStays();
  const newStay: Stay = {
    ...stay,
    id: crypto.randomUUID(),
    createdAt: Date.now(),
  };
  const updatedStays = [newStay, ...currentStays];
  localStorage.setItem(STORAGE_KEY, JSON.stringify(updatedStays));
  return newStay;
};

export const updateStay = (id: string, updates: Partial<Stay>): Stay | null => {
  const currentStays = getStays();
  const index = currentStays.findIndex(s => s.id === id);
  if (index === -1) return null;

  const updatedStay = { ...currentStays[index], ...updates };
  currentStays[index] = updatedStay;
  localStorage.setItem(STORAGE_KEY, JSON.stringify(currentStays));
  return updatedStay;
};

export const deleteStay = (id: string): void => {
  const currentStays = getStays();
  const updatedStays = currentStays.filter(s => s.id !== id);
  localStorage.setItem(STORAGE_KEY, JSON.stringify(updatedStays));
};

export const importStays = (newStays: Stay[]): void => {
  // Simple validation to ensure it looks like our data
  const validStays = newStays.filter(s => s.hotelName && s.brand && s.date);
  localStorage.setItem(STORAGE_KEY, JSON.stringify(validStays));
};

