export const getStays = (): Stay[] => {
  const data = localStorage.getItem(STORAGE_KEY);
  if (!data) {
    // Initialize with dummy data for better first-time UX
    localStorage.setItem(STORAGE_KEY, JSON.stringify(INITIAL_DATA));
    return INITIAL_DATA;
  }
  try {
    const parsed = JSON.parse(data);
    // Migration for old data structures
    return parsed.map((s: any) => {
        // Handle migration from old 'date' field to checkIn/checkOut
        const checkIn = s.checkInDate || s.date;
        const checkOut = s.checkOutDate || (checkIn ? addDays(checkIn, 1) : '');

        return {
            ...s,
            checkInDate: checkIn,
            checkOutDate: checkOut,
            country: s.country || 'Unknown' 
        };
    });
  } catch (e) {
    return [];
  }
};

export const addStay = (stay: Omit<Stay, 'id' | 'createdAt'>): Stay => {
  const currentStays = getStays();
  const newStay: Stay = {
    ...stay,
    id: crypto.randomUUID(),
    createdAt: Date.now(),
  };
  const updatedStays = [newStay, ...currentStays];
  localStorage.setItem(STORAGE_KEY, JSON.stringify(updatedStays));
  return newStay;
};

export const updateStay = (id: string, updates: Partial<Stay>): Stay | null => {
  const currentStays = getStays();
  const index = currentStays.findIndex(s => s.id === id);
  if (index === -1) return null;

  const updatedStay = { ...currentStays[index], ...updates };
  currentStays[index] = updatedStay;
  localStorage.setItem(STORAGE_KEY, JSON.stringify(currentStays));
  return updatedStay;
};

export const deleteStay = (id: string): void => {
  const currentStays = getStays();
  const updatedStays = currentStays.filter(s => s.id !== id);
  localStorage.setItem(STORAGE_KEY, JSON.stringify(updatedStays));
};

export const importStays = (newStays: Stay[]): void => {
  // Simple validation to ensure it looks like our data
  // Map old formats if importing from older export
  const processedStays = newStays.map((s: any) => ({
      ...s,
      checkInDate: s.checkInDate || s.date,
      checkOutDate: s.checkOutDate || (s.date ? addDays(s.date, 1) : '')
  })).filter(s => s.hotelName && s.brand && s.checkInDate);

  localStorage.setItem(STORAGE_KEY, JSON.stringify(processedStays));
};

import React, { useState, useEffect, useRef } from 'react';
import { Plus, X, Save, ChevronLeft, ChevronRight, Calendar as CalendarIcon, Moon } from 'lucide-react';
import { Stay } from '../types';
import { POPULAR_BRANDS } from '../constants';

interface StayFormProps {
  initialData?: Stay;
  onSave: (stay: Omit<Stay, 'id' | 'createdAt'>) => void;
  onClose: () => void;
}

// Helper to format date for display
const formatDate = (date: Date) => date.toISOString().split('T')[0];

const DateRangePicker: React.FC<{
  checkIn: string;
  checkOut: string;
  onChange: (start: string, end: string) => void;
}> = ({ checkIn, checkOut, onChange }) => {
  const [currentMonth, setCurrentMonth] = useState(new Date(checkIn || new Date()));
  const [hoverDate, setHoverDate] = useState<Date | null>(null);
  const [isOpen, setIsOpen] = useState(false);
  const containerRef = useRef<HTMLDivElement>(null);

  // Close calendar when clicking outside
  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (containerRef.current && !containerRef.current.contains(event.target as Node)) {
        setIsOpen(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  const getDaysInMonth = (date: Date) => {
    const year = date.getFullYear();
    const month = date.getMonth();
    const days = new Date(year, month + 1, 0).getDate();
    const firstDay = new Date(year, month, 1).getDay();
    return { days, firstDay, year, month };
  };

  const { days, firstDay, year, month } = getDaysInMonth(currentMonth);

  const prevMonth = () => setCurrentMonth(new Date(year, month - 1, 1));
  const nextMonth = () => setCurrentMonth(new Date(year, month + 1, 1));

  const handleDateClick = (day: number) => {
    const clickedDate = new Date(year, month, day);
    const clickedStr = formatDate(clickedDate);

    // Logic:
    // 1. If nothing selected, set checkIn.
    // 2. If checkIn selected but no checkOut, set checkOut (if after checkIn), else reset to checkIn.
    // 3. If both selected, reset to checkIn.

    if (!checkIn || (checkIn && checkOut)) {
      onChange(clickedStr, '');
    } else if (checkIn && !checkOut) {
      if (clickedDate > new Date(checkIn)) {
        onChange(checkIn, clickedStr);
        setIsOpen(false); // Close on selection complete
      } else {
        onChange(clickedStr, ''); // Reset start date if clicked before
      }
    }
  };

  const isSelected = (day: number) => {
    const d = new Date(year, month, day).getTime();
    const start = checkIn ? new Date(checkIn).getTime() : 0;
    const end = checkOut ? new Date(checkOut).getTime() : 0;
    return d === start || d === end;
  };

  const isInRange = (day: number) => {
    const d = new Date(year, month, day).getTime();
    const start = checkIn ? new Date(checkIn).getTime() : 0;
    const end = checkOut ? new Date(checkOut).getTime() : 0;
    const hover = hoverDate ? hoverDate.getTime() : 0;

    // Fixed range
    if (start && end) return d > start && d < end;

    // Hover range (visual blue path)
    if (start && !end && hover) {
      return d > start && d <= hover;
    }
    return false;
  };

  const isStart = (day: number) => {
    if (!checkIn) return false;
    const d = new Date(year, month, day).getTime();
    return d === new Date(checkIn).getTime();
  };

  const isEnd = (day: number) => {
     const d = new Date(year, month, day).getTime();
     if (checkOut && d === new Date(checkOut).getTime()) return true;
     // Show end style on hover if valid
     if (checkIn && !checkOut && hoverDate) {
        return d === hoverDate.getTime() && d > new Date(checkIn).getTime();
     }
     return false;
  };

  const nights = checkIn && checkOut 
    ? Math.round((new Date(checkOut).getTime() - new Date(checkIn).getTime()) / (1000 * 60 * 60 * 24)) 
    : 0;

  return (
    <div className="relative" ref={containerRef}>
      <label className="block text-sm font-medium text-slate-700 mb-2">Duration of Stay</label>
      <div 
        onClick={() => setIsOpen(!isOpen)}
        className="w-full px-4 py-3 border border-slate-300 rounded-lg flex items-center justify-between cursor-pointer hover:border-indigo-500 hover:ring-2 hover:ring-indigo-100 transition-all bg-white"
      >
        <div className="flex items-center gap-2 text-slate-700">
           <CalendarIcon size={18} className="text-indigo-600" />
           {checkIn ? (
             <span className="font-medium">
               {new Date(checkIn).toLocaleDateString(undefined, { month: 'short', day: 'numeric' })}
               {checkOut ? ` - ${new Date(checkOut).toLocaleDateString(undefined, { month: 'short', day: 'numeric' })}` : ' - Check-out?'}
             </span>
           ) : (
             <span className="text-slate-400">Select Dates</span>
           )}
        </div>
        {nights > 0 && (
          <span className="bg-indigo-100 text-indigo-700 text-xs font-bold px-2 py-1 rounded-full flex items-center gap-1">
            <Moon size={10} /> {nights} Nights
          </span>
        )}
      </div>

      {isOpen && (
        <div className="absolute top-full left-0 mt-2 bg-white rounded-xl shadow-2xl border border-slate-100 p-4 z-50 w-full animate-fade-in-up">
           <div className="flex justify-between items-center mb-4">
              <button type="button" onClick={prevMonth} className="p-1 hover:bg-slate-100 rounded-full"><ChevronLeft size={20} /></button>
              <span className="font-bold text-slate-700">{currentMonth.toLocaleString('default', { month: 'long', year: 'numeric' })}</span>
              <button type="button" onClick={nextMonth} className="p-1 hover:bg-slate-100 rounded-full"><ChevronRight size={20} /></button>
           </div>

           <div className="grid grid-cols-7 gap-1 text-center mb-2">
              {['S','M','T','W','T','F','S'].map(d => <span key={d} className="text-xs font-bold text-slate-400">{d}</span>)}
           </div>

           <div className="grid grid-cols-7 gap-1">
              {Array.from({ length: firstDay }).map((_, i) => <div key={`empty-${i}`} />)}
              {Array.from({ length: days }).map((_, i) => {
                 const day = i + 1;
                 const selected = isSelected(day);
                 const range = isInRange(day);
                 const start = isStart(day);
                 const end = isEnd(day);

                 let baseClass = "h-9 w-9 flex items-center justify-center text-sm rounded-full transition-all cursor-pointer relative z-10 ";
                 if (start || end) baseClass += "bg-indigo-600 text-white font-bold shadow-md transform scale-105 ";
                 else if (range) baseClass += "bg-indigo-100 text-indigo-700 font-medium ";
                 else baseClass += "text-slate-700 hover:bg-slate-100 ";

                 return (
                   <div 
                      key={day} 
                      className="relative p-0.5"
                      onMouseEnter={() => setHoverDate(new Date(year, month, day))}
                   >
                      {/* Connector line for range visualization */}
                      {range && !start && !end && (
                        <div className="absolute inset-y-2 left-0 right-0 bg-indigo-100 z-0"></div>
                      )}
                      {range && start && (
                        <div className="absolute inset-y-2 left-1/2 right-0 bg-indigo-100 z-0 rounded-l-none"></div>
                      )}
                      {range && end && (
                        <div className="absolute inset-y-2 left-0 right-1/2 bg-indigo-100 z-0 rounded-r-none"></div>
                      )}

                      <button
                        type="button"
                        onClick={() => handleDateClick(day)}
                        className={baseClass}
                      >
                        {day}
                      </button>
                   </div>
                 );
              })}
           </div>
           <div className="mt-4 pt-3 border-t border-slate-100 flex justify-between text-xs text-slate-500">
              <span>Check-in: {checkIn || '-'}</span>
              <span>Check-out: {checkOut || '-'}</span>
           </div>
        </div>
      )}
    </div>
  );
};

export const StayForm: React.FC<StayFormProps> = ({ initialData, onSave, onClose }) => {
  const [hotelName, setHotelName] = useState('');
  const [brand, setBrand] = useState('');
  const [country, setCountry] = useState('');
  const [checkIn, setCheckIn] = useState('');
  const [checkOut, setCheckOut] = useState('');
  const [customBrand, setCustomBrand] = useState(false);

  useEffect(() => {
    if (initialData) {
      setHotelName(initialData.hotelName);
      setBrand(initialData.brand);
      setCountry(initialData.country);
      setCheckIn(initialData.checkInDate);
      setCheckOut(initialData.checkOutDate);
      if (!POPULAR_BRANDS.includes(initialData.brand)) {
        setCustomBrand(true);
      }
    } else {
        // Default to today
        const today = new Date().toISOString().split('T')[0];
        setCheckIn(today);
    }
  }, [initialData]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (hotelName && brand && checkIn && checkOut && country) {
      onSave({ 
        hotelName, 
        brand, 
        country, 
        checkInDate: checkIn,
        checkOutDate: checkOut 
      });
      onClose();
    }
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50 backdrop-blur-sm p-4">
      <div className="bg-white rounded-2xl shadow-xl w-full max-w-md overflow-hidden animate-fade-in-up flex flex-col max-h-[90vh]">
        <div className="bg-indigo-600 p-6 text-white flex justify-between items-center shrink-0">
          <h2 className="text-xl font-bold">{initialData ? 'Edit Stay' : 'Add New Stay'}</h2>
          <button onClick={onClose} className="hover:bg-indigo-700 p-1 rounded-full transition-colors">
            <X size={20} />
          </button>
        </div>

        <form onSubmit={handleSubmit} className="p-6 space-y-6 overflow-y-auto custom-scrollbar">
          <div className="space-y-2">
            <label className="block text-sm font-medium text-slate-700">Hotel Name</label>
            <input
              type="text"
              value={hotelName}
              onChange={(e) => setHotelName(e.target.value)}
              placeholder="e.g. Grand Hyatt Tokyo"
              className="w-full px-4 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 outline-none transition-all"
              required
            />
          </div>

          <div className="space-y-2">
            <label className="block text-sm font-medium text-slate-700">Country</label>
            <input
              type="text"
              value={country}
              onChange={(e) => setCountry(e.target.value)}
              placeholder="e.g. Japan"
              className="w-full px-4 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none"
              required
            />
          </div>

          <div className="space-y-2">
            <label className="block text-sm font-medium text-slate-700">Brand Portfolio</label>
            {!customBrand ? (
              <div className="grid grid-cols-2 gap-2">
                 <select 
                    value={brand} 
                    onChange={(e) => {
                        if (e.target.value === 'Other') {
                            setCustomBrand(true);
                            setBrand('');
                        } else {
                            setBrand(e.target.value);
                        }
                    }}
                    className="col-span-2 w-full px-4 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none"
                 >
                    <option value="" disabled>Select a Loyalty Program</option>
                    {POPULAR_BRANDS.map(b => <option key={b} value={b}>{b}</option>)}
                    <option value="Other">Other (Type custom)</option>
                 </select>
              </div>
            ) : (
              <div className="flex gap-2">
                <input
                  type="text"
                  value={brand}
                  onChange={(e) => setBrand(e.target.value)}
                  placeholder="Enter Brand Name"
                  className="w-full px-4 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none"
                  autoFocus
                  required
                />
                <button 
                    type="button" 
                    onClick={() => setCustomBrand(false)}
                    className="text-xs text-slate-500 underline whitespace-nowrap"
                >
                    Back to list
                </button>
              </div>
            )}
          </div>

          {/* Custom Date Range Picker */}
          <DateRangePicker 
            checkIn={checkIn} 
            checkOut={checkOut} 
            onChange={(start, end) => {
                setCheckIn(start);
                setCheckOut(end);
            }} 
          />

          <div className="pt-4">
            <button
              type="submit"
              className="w-full bg-indigo-600 text-white font-semibold py-3 rounded-xl hover:bg-indigo-700 transition-all shadow-lg shadow-indigo-200 flex items-center justify-center gap-2"
            >
              {initialData ? <Save size={20} /> : <Plus size={20} />}
              {initialData ? 'Save Changes' : 'Add to Portfolio'}
            </button>
          </div>
        </form>
      </div>
    </div>
  );
};

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { LayoutDashboard, Briefcase, Share2, Plus, Hotel, Trash2, Pencil, Download, Upload, Moon } from 'lucide-react';
import { Stay, ViewMode, StatSummary } from './types';
import { getStays, addStay, deleteStay, updateStay, importStays } from './services/storage';
import { StayForm } from './components/StayForm';
import { BrandPortfolio } from './components/BrandPortfolio';
import { ShareView } from './components/ShareView';

const App: React.FC = () => {
  const [stays, setStays] = useState<Stay[]>([]);
  const [view, setView] = useState<ViewMode>('dashboard');
  const [isFormOpen, setIsFormOpen] = useState(false);
  const [editingStay, setEditingStay] = useState<Stay | undefined>(undefined);
  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    setStays(getStays());
  }, []);

  const handleSaveStay = (stayData: Omit<Stay, 'id' | 'createdAt'>) => {
    if (editingStay) {
      const updated = updateStay(editingStay.id, stayData);
      if (updated) {
        setStays(prev => prev.map(s => s.id === updated.id ? updated : s));
      }
    } else {
      const newStay = addStay(stayData);
      setStays(prev => [newStay, ...prev]);
    }
  };

  const handleDeleteStay = (id: string) => {
    deleteStay(id);
    setStays(prev => prev.filter(s => s.id !== id));
  };

  const handleEditClick = (stay: Stay) => {
    setEditingStay(stay);
    setIsFormOpen(true);
  };

  const handleCloseForm = () => {
    setIsFormOpen(false);
    setEditingStay(undefined);
  };

  const handleExport = () => {
    const dataStr = "data:text/json;charset=utf-8," + encodeURIComponent(JSON.stringify(stays));
    const downloadAnchorNode = document.createElement('a');
    downloadAnchorNode.setAttribute("href", dataStr);
    downloadAnchorNode.setAttribute("download", "stayfolio_data.json");
    document.body.appendChild(downloadAnchorNode);
    downloadAnchorNode.click();
    downloadAnchorNode.remove();
  };

  const handleImportClick = () => {
    fileInputRef.current?.click();
  };

  const handleFileChange = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = (e) => {
        try {
          const json = JSON.parse(e.target?.result as string);
          if (Array.isArray(json)) {
             importStays(json);
             setStays(getStays()); // Refresh from storage
             alert('Data imported successfully!');
          }
        } catch (error) {
          alert('Error parsing JSON file');
        }
      };
      reader.readAsText(file);
    }
    // Reset input
    if (event.target) event.target.value = '';
  };

  const stats: StatSummary = useMemo(() => {
    const uniqueBrands = new Set(stays.map(s => s.brand));
    const brandCounts: Record<string, number> = {};

    let totalNights = 0;
    stays.forEach(s => {
        brandCounts[s.brand] = (brandCounts[s.brand] || 0) + 1;
        if (s.checkInDate && s.checkOutDate) {
            const start = new Date(s.checkInDate).getTime();
            const end = new Date(s.checkOutDate).getTime();
            const nights = Math.round((end - start) / (1000 * 60 * 60 * 24));
            totalNights += Math.max(0, nights);
        }
    });

    const topBrand = Object.entries(brandCounts).sort((a, b) => b[1] - a[1])[0]?.[0] || '';

    return {
      totalStays: stays.length,
      totalNights,
      uniqueBrands: uniqueBrands.size,
      topBrand,
      thisYearStays: stays.filter(s => new Date(s.checkInDate).getFullYear() === new Date().getFullYear()).length
    };
  }, [stays]);

  // Helper to format date range
  const formatStayDate = (start: string, end: string) => {
    const s = new Date(start);
    const e = new Date(end);
    const nights = Math.round((e.getTime() - s.getTime()) / (1000 * 60 * 60 * 24));

    return {
        dateStr: `${s.toLocaleDateString(undefined, {month: 'short', day: 'numeric'})} - ${e.toLocaleDateString(undefined, {month: 'short', day: 'numeric'})}`,
        nights: Math.max(0, nights)
    };
  };

  return (
    <div className="min-h-screen pb-20 md:pb-0">
      {/* Header */}
      <header className="bg-white sticky top-0 z-30 border-b border-slate-200">
        <div className="max-w-3xl mx-auto px-4 h-16 flex items-center justify-between">
          <div className="flex items-center gap-2 text-indigo-600">
            <div className="bg-indigo-600 p-1.5 rounded-lg text-white">
                <Hotel size={20} />
            </div>
            <h1 className="font-bold text-xl tracking-tight text-slate-900 hidden xs:block">StayFolio</h1>
          </div>

          <div className="flex items-center gap-2">
            <div className="text-xs font-medium text-slate-500 bg-slate-100 px-3 py-1.5 rounded-full mr-2 hidden sm:block">
              {stats.totalNights} Nights • {stats.totalStays} Stays
            </div>
            <button onClick={handleExport} className="p-2 text-slate-400 hover:text-indigo-600 hover:bg-indigo-50 rounded-full transition-colors" title="Export Data">
                <Download size={18} />
            </button>
            <button onClick={handleImportClick} className="p-2 text-slate-400 hover:text-indigo-600 hover:bg-indigo-50 rounded-full transition-colors" title="Import Data">
                <Upload size={18} />
            </button>
            <input 
                type="file" 
                ref={fileInputRef} 
                onChange={handleFileChange} 
                className="hidden" 
                accept=".json"
            />
          </div>
        </div>
      </header>

      {/* Main Content */}
      <main className="max-w-3xl mx-auto px-4 py-6">

        {/* Dashboard View */}
        {view === 'dashboard' && (
          <div className="space-y-6">
            <div className="grid grid-cols-3 gap-4">
                <div className="bg-white p-4 rounded-2xl shadow-sm border border-slate-100 text-center">
                    <span className="block text-3xl font-bold text-slate-800">{stats.totalNights}</span>
                    <span className="text-xs text-slate-500 font-medium uppercase tracking-wide">Total Nights</span>
                </div>
                <div className="bg-white p-4 rounded-2xl shadow-sm border border-slate-100 text-center">
                    <span className="block text-3xl font-bold text-indigo-600">{stats.thisYearStays}</span>
                    <span className="text-xs text-slate-500 font-medium uppercase tracking-wide">Stays (YTD)</span>
                </div>
                <div className="bg-white p-4 rounded-2xl shadow-sm border border-slate-100 text-center">
                    <span className="block text-3xl font-bold text-slate-800">{stats.topBrand ? stats.topBrand.slice(0, 8) : '-'}</span>
                    <span className="text-xs text-slate-500 font-medium uppercase tracking-wide">Top Loyalty</span>
                </div>
            </div>

            <div className="flex justify-between items-end">
                <h2 className="text-lg font-bold text-slate-800">Recent Activity</h2>
                <button 
                    onClick={() => { setEditingStay(undefined); setIsFormOpen(true); }}
                    className="text-indigo-600 text-sm font-medium hover:bg-indigo-50 px-3 py-1 rounded-lg transition-colors flex items-center gap-1"
                >
                    <Plus size={16} /> Add Stay
                </button>
            </div>

            <div className="space-y-3 pb-20">
                {stays.length === 0 ? (
                     <div className="text-center py-12 bg-white rounded-2xl border-2 border-dashed border-slate-200">
                        <p className="text-slate-400">No stays yet. Start tracking your journey!</p>
                        <button onClick={() => setIsFormOpen(true)} className="mt-4 px-6 py-2 bg-indigo-600 text-white rounded-lg text-sm font-medium">Add First Stay</button>
                    </div>
                ) : (
                    stays.map(stay => {
                        const { dateStr, nights } = formatStayDate(stay.checkInDate, stay.checkOutDate);
                        return (
                            <div key={stay.id} className="bg-white p-4 rounded-xl shadow-sm border border-slate-100 flex justify-between items-center group">
                                <div className="flex items-center gap-4">
                                    <div className="w-12 h-12 rounded-full bg-indigo-50 flex items-center justify-center text-indigo-600 font-bold text-lg shrink-0">
                                        {stay.brand.charAt(0)}
                                    </div>
                                    <div className="min-w-0">
                                        <h3 className="font-semibold text-slate-800 truncate">{stay.hotelName}</h3>
                                        <div className="flex items-center gap-2 text-sm text-slate-500">
                                            <span className="font-medium text-slate-600 shrink-0">{stay.brand}</span>
                                            <span>•</span>
                                            <span className="truncate">{stay.country}</span>
                                        </div>
                                        <div className="flex items-center gap-2 text-xs text-slate-400 mt-0.5">
                                            <span className="shrink-0">{dateStr}</span>
                                            <span className="bg-slate-100 text-slate-600 px-1.5 py-0.5 rounded-full flex items-center gap-0.5">
                                                <Moon size={8} /> {nights}n
                                            </span>
                                        </div>
                                    </div>
                                </div>
                                <div className="flex items-center gap-1 opacity-100 md:opacity-0 group-hover:opacity-100 transition-all">
                                    <button 
                                        onClick={() => handleEditClick(stay)}
                                        className="text-slate-300 hover:text-indigo-600 p-2 transition-colors"
                                        title="Edit"
                                    >
                                        <Pencil size={18} />
                                    </button>
                                    <button 
                                        onClick={() => handleDeleteStay(stay.id)}
                                        className="text-slate-300 hover:text-red-500 p-2 transition-colors"
                                        title="Delete"
                                    >
                                        <Trash2 size={18} />
                                    </button>
                                </div>
                            </div>
                        );
                    })
                )}
            </div>
          </div>
        )}

        {/* Portfolio View */}
        {view === 'portfolio' && (
             <BrandPortfolio stays={stays} />
        )}

        {/* Share View */}
        {view === 'share' && (
            <ShareView stays={stays} summary={stats} />
        )}

      </main>

      {/* Floating Action Button for Mobile Add */}
      {view === 'dashboard' && (
         <button 
            onClick={() => { setEditingStay(undefined); setIsFormOpen(true); }}
            className="md:hidden fixed bottom-24 right-6 bg-indigo-600 text-white p-4 rounded-full shadow-xl hover:bg-indigo-700 transition-transform active:scale-95 z-20"
         >
            <Plus size={24} />
         </button>
      )}

      {/* Bottom Navigation */}
      <nav className="fixed bottom-0 w-full bg-white border-t border-slate-200 py-3 px-6 md:px-0 z-30">
        <div className="max-w-xl mx-auto flex justify-between md:justify-center md:gap-12">
            <NavButton 
                active={view === 'dashboard'} 
                onClick={() => setView('dashboard')} 
                icon={<LayoutDashboard size={24} />} 
                label="My Stays" 
            />
            <NavButton 
                active={view === 'portfolio'} 
                onClick={() => setView('portfolio')} 
                icon={<Briefcase size={24} />} 
                label="Portfolio" 
            />
            <NavButton 
                active={view === 'share'} 
                onClick={() => setView('share')} 
                icon={<Share2 size={24} />} 
                label="Share" 
            />
        </div>
      </nav>

      {/* Modals */}
      {isFormOpen && (
        <StayForm 
            initialData={editingStay}
            onSave={handleSaveStay} 
            onClose={handleCloseForm} 
        />
      )}
    </div>
  );
};

const NavButton: React.FC<{ active: boolean; onClick: () => void; icon: React.ReactNode; label: string }> = ({ active, onClick, icon, label }) => (
    <button 
        onClick={onClick}
        className={`flex flex-col items-center gap-1 transition-colors ${active ? 'text-indigo-600' : 'text-slate-400 hover:text-slate-600'}`}
    >
        {icon}
        <span className="text-[10px] font-medium uppercase tracking-wide">{label}</span>
    </button>
);

export default App;

import React, { useMemo, useState } from 'react';
import { BrandGroup, Stay } from '../types';
import { Building2, Calendar, Moon } from 'lucide-react';
import { BRAND_LOGOS } from '../constants';

interface BrandPortfolioProps {
  stays: Stay[];
}

const BrandLogo: React.FC<{ brand: string }> = ({ brand }) => {
  const [error, setError] = useState(false);
  const logoUrl = BRAND_LOGOS[brand];

  if (logoUrl && !error) {
    return (
      <img 
        src={logoUrl} 
        alt={brand} 
        onError={() => setError(true)}
        className="h-full w-auto object-contain max-w-[150px]" 
      />
    );
  }

  return (
    <div className="flex items-center gap-2 text-slate-700">
        <Building2 size={24} className="opacity-70" />
        <h3 className="font-bold text-lg">{brand}</h3>
    </div>
  );
};

export const BrandPortfolio: React.FC<BrandPortfolioProps> = ({ stays }) => {
  const brandGroups: BrandGroup[] = useMemo(() => {
    const groups: Record<string, Stay[]> = {};
    stays.forEach(stay => {
      const b = stay.brand || 'Unbranded';
      if (!groups[b]) groups[b] = [];
      groups[b].push(stay);
    });

    return Object.entries(groups)
      .map(([brand, stays]) => ({
        brand,
        count: stays.length,
        stays: stays.sort((a, b) => new Date(b.checkInDate).getTime() - new Date(a.checkInDate).getTime())
      }))
      .sort((a, b) => b.count - a.count);
  }, [stays]);

  return (
    <div className="space-y-6 pb-20">
      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
        {brandGroups.map((group) => (
          <div key={group.brand} className="bg-white rounded-2xl shadow-sm border border-slate-100 overflow-hidden hover:shadow-md transition-shadow group">
            <div className="p-5 border-b border-slate-50 flex justify-between items-center bg-slate-50/50">
               <div className="h-12 flex items-center">
                  <BrandLogo brand={group.brand} />
               </div>
               <span className="bg-indigo-100 text-indigo-700 px-3 py-1 rounded-full text-xs font-bold">
                  {group.count} {group.count === 1 ? 'Stay' : 'Stays'}
                </span>
            </div>

            <div className="p-4 max-h-60 overflow-y-auto space-y-3 custom-scrollbar bg-white">
              {group.stays.map(stay => {
                const s = new Date(stay.checkInDate);
                const e = new Date(stay.checkOutDate);
                const nights = Math.max(0, Math.round((e.getTime() - s.getTime()) / (1000 * 60 * 60 * 24)));

                return (
                    <div key={stay.id} className="flex items-center gap-4 p-3 rounded-lg border border-slate-50 hover:bg-slate-50 transition-colors">
                    <div className="w-10 h-10 rounded-full bg-slate-100 flex items-center justify-center text-slate-400">
                        <Building2 size={16} />
                    </div>
                    <div className="flex-1">
                        <p className="font-semibold text-slate-800 text-sm">{stay.hotelName}</p>
                        <div className="flex items-center gap-3 text-xs text-slate-500 mt-0.5">
                            <div className="flex items-center gap-1">
                                <Calendar size={12} />
                                <span>{s.toLocaleDateString(undefined, {month: 'short', day: 'numeric'})} - {e.toLocaleDateString(undefined, {month: 'short', day: 'numeric'})}</span>
                            </div>
                            <div className="flex items-center gap-1 text-slate-400">
                                <Moon size={10} />
                                <span>{nights}n</span>
                            </div>
                        </div>
                    </div>
                    </div>
                );
              })}
            </div>

            <div className="bg-slate-50/80 p-2 text-center border-t border-slate-100">
               <div className="w-full h-1 bg-slate-200 rounded-full overflow-hidden">
                  <div 
                      className="h-full bg-indigo-500 rounded-full" 
                      style={{ width: `${(group.count / stays.length) * 100}%` }}
                  ></div>
               </div>
            </div>
