    const dayCounts = Array(7).fill(0);

    stays.forEach(stay => {
      // Groups
      const b = stay.brand || 'Unbranded';
      if (!groups[b]) groups[b] = [];
      groups[b].push(stay);

      // Nights
      const s = new Date(stay.checkInDate);
      const e = new Date(stay.checkOutDate);
      const n = Math.max(0, Math.round((e.getTime() - s.getTime()) / (1000 * 60 * 60 * 24)));
      nightsSum += n;

      // Countries
      const c = stay.country || 'Unknown';
      countryCounts[c] = (countryCounts[c] || 0) + 1;

      // Hotels
      hotelCounts[stay.hotelName] = (hotelCounts[stay.hotelName] || 0) + 1;

      // Cost
      const cost = stay.cost || 0;
      costSum += cost;
      if (cost > 0) {
        if (!maxCostStay || cost > (maxCostStay.cost || 0)) maxCostStay = stay;
        if (!minCostStay || cost < (minCostStay.cost || 0)) minCostStay = stay;
      }

      // Charts
      monthCounts[s.getMonth()]++;
      const day = s.getDay(); // 0 is Sunday
      // Adjust to Mon(0) - Sun(6) for better chart reading usually, but let's stick to standard 0=Sun
      dayCounts[day]++;
    });

    const sortedGroups = Object.entries(groups)
      .map(([brand, stays]) => ({
        brand,
        count: stays.length,
        stays: stays.sort((a, b) => new Date(b.checkInDate).getTime() - new Date(a.checkInDate).getTime())
      }))
      .sort((a, b) => b.count - a.count);

    const sortedCountries = Object.entries(countryCounts).sort((a, b) => b[1] - a[1]);
    const sortedHotels = Object.entries(hotelCounts).sort((a, b) => b[1] - a[1]);

    // Chart Formatting
    const monthNames = ["Jan", "Feb", "Mar", "Apr", "May", "Jun", "Jul", "Aug", "Sep", "Oct", "Nov", "Dec"];
    const dayNames = ["Sun", "Mon", "Tue", "Wed", "Thu", "Fri", "Sat"];

    const formattedChartData = chartMode === 'month' 
        ? monthCounts.map((count, i) => ({ name: monthNames[i], stays: count }))
        : dayCounts.map((count, i) => ({ name: dayNames[i], stays: count }));

    return {
      brandGroups: sortedGroups,
      totalNights: nightsSum,
      totalBrands: Object.keys(groups).length,
      countriesVisited: Object.keys(countryCounts).length,
      topCountry: sortedCountries[0],
      topHotel: sortedHotels[0],
      chartData: formattedChartData,
      financial: {
        total: costSum,
        avgNight: nightsSum > 0 ? costSum / nightsSum : 0,
        maxStay: maxCostStay,
        minStay: minCostStay
      }
    };
  }, [stays, chartMode]);

  // --- Satire Generator ---
  const getSatire = (nights: number) => {
    if (nights === 0) return "You are officially a couch potato. The hotels miss you (and your wallet).";
    if (nights < 7) return "Rookie numbers. You've barely scratched the surface of the mini-bar.";
    if (nights < 21) return "A respectable vacationer. But do you even have status yet?";
    if (nights < 50) return "Wow, look at you! Digital Nomad or just avoiding responsibilities?";
    if (nights < 100) return "Your neighbors have filed a missing persons report. The hotel staff knows your coffee order better than your spouse.";
    return "365 days is the goal, right? You should probably start paying rent to Marriott instead of your landlord.";
  };

  return (
    <div className="space-y-10 pb-20">

