                                <Cell key={`cell-${index}`} fill={entry.stays > 0 ? '#4f46e5' : '#e2e8f0'} />
                            ))}
                        </Bar>
                    </BarChart>
                </ResponsiveContainer>
             </div>
         </div>
      </div>

      {/* SECTION 2: Satire & Records */}
      <div className="space-y-6">
         <div className="flex items-center gap-2 mb-2">
             <div className="h-6 w-1 bg-rose-500 rounded-full"></div>
