                                <p className="font-semibold text-slate-800 text-sm truncate">{stay.hotelName}</p>
                                {stay.cost ? <span className="text-xs font-medium text-emerald-600 bg-emerald-50 px-1.5 py-0.5 rounded">${stay.cost}</span> : null}
