             <div className="grid grid-cols-1 md:grid-cols-3 divide-y md:divide-y-0 md:divide-x divide-slate-100">
                 <div className="p-5">
                    <p className="text-xs font-bold text-slate-400 uppercase mb-1">Average / Night</p>
