import React, { useState, useEffect, useMemo, useRef } from 'react';
import { LayoutDashboard, Briefcase, Share2, Plus, Hotel, Trash2, Pencil, Download, Upload, Moon } from 'lucide-react';
import { Stay, ViewMode, StatSummary } from './types';
import { getStays, addStay, deleteStay, updateStay, importStays } from './services/storage';
import { StayForm } from './components/StayForm';
import { BrandPortfolio } from './components/BrandPortfolio';
import { ShareView } from './components/ShareView';

const App: React.FC = () => {
  const [stays, setStays] = useState<Stay[]>([]);
  const [view, setView] = useState<ViewMode>('portfolio'); // Default to Portfolio now as it is 1st item
  const [isFormOpen, setIsFormOpen] = useState(false);
  const [editingStay, setEditingStay] = useState<Stay | undefined>(undefined);
  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    setStays(getStays());
  }, []);

  const handleSaveStay = (stayData: Omit<Stay, 'id' | 'createdAt'>) => {
    if (editingStay) {
      const updated = updateStay(editingStay.id, stayData);
      if (updated) {
        setStays(prev => prev.map(s => s.id === updated.id ? updated : s));
      }
    } else {
      const newStay = addStay(stayData);
      setStays(prev => [newStay, ...prev]);
    }
  };

  const handleDeleteStay = (id: string) => {
    deleteStay(id);
    setStays(prev => prev.filter(s => s.id !== id));
  };

  const handleEditClick = (stay: Stay) => {
    setEditingStay(stay);
    setIsFormOpen(true);
  };

  const handleCloseForm = () => {
    setIsFormOpen(false);
    setEditingStay(undefined);
  };

  const handleExport = () => {
    const dataStr = "data:text/json;charset=utf-8," + encodeURIComponent(JSON.stringify(stays));
    const downloadAnchorNode = document.createElement('a');
    downloadAnchorNode.setAttribute("href", dataStr);
    downloadAnchorNode.setAttribute("download", "stayfolio_data.json");
    document.body.appendChild(downloadAnchorNode);
    downloadAnchorNode.click();
    downloadAnchorNode.remove();
  };

  const handleImportClick = () => {
    fileInputRef.current?.click();
  };

  const handleFileChange = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = (e) => {
        try {
          const json = JSON.parse(e.target?.result as string);
          if (Array.isArray(json)) {
             importStays(json);
             setStays(getStays()); // Refresh from storage
             alert('Data imported successfully!');
          }
        } catch (error) {
          alert('Error parsing JSON file');
        }
      };
      reader.readAsText(file);
    }
    // Reset input
    if (event.target) event.target.value = '';
  };

  const stats: StatSummary = useMemo(() => {
    const uniqueBrands = new Set(stays.map(s => s.brand));
    const brandCounts: Record<string, number> = {};

    let totalNights = 0;
    stays.forEach(s => {
        brandCounts[s.brand] = (brandCounts[s.brand] || 0) + 1;
        if (s.checkInDate && s.checkOutDate) {
            const start = new Date(s.checkInDate).getTime();
            const end = new Date(s.checkOutDate).getTime();
            const nights = Math.round((end - start) / (1000 * 60 * 60 * 24));
            totalNights += Math.max(0, nights);
        }
    });

    const topBrand = Object.entries(brandCounts).sort((a, b) => b[1] - a[1])[0]?.[0] || '';

    return {
      totalStays: stays.length,
      totalNights,
      uniqueBrands: uniqueBrands.size,
      topBrand,
      thisYearStays: stays.filter(s => new Date(s.checkInDate).getFullYear() === new Date().getFullYear()).length
    };
  }, [stays]);

  // Helper to format date range
  const formatStayDate = (start: string, end: string) => {
    const s = new Date(start);
    const e = new Date(end);
    const nights = Math.round((e.getTime() - s.getTime()) / (1000 * 60 * 60 * 24));

    return {
        dateStr: `${s.toLocaleDateString(undefined, {month: 'short', day: 'numeric'})} - ${e.toLocaleDateString(undefined, {month: 'short', day: 'numeric'})}`,
        nights: Math.max(0, nights)
    };
  };

  return (
    <div className="min-h-screen pb-20 md:pb-0">
      {/* Header */}
      <header className="bg-white sticky top-0 z-30 border-b border-slate-200">
        <div className="max-w-3xl mx-auto px-4 h-16 flex items-center justify-between">
          <div className="flex items-center gap-2 text-indigo-600">
            <div className="bg-indigo-600 p-1.5 rounded-lg text-white">
                <Hotel size={20} />
            </div>
            <h1 className="font-bold text-xl tracking-tight text-slate-900">StayFolio</h1>
          </div>

          <div className="flex items-center gap-2">
            <div className="text-xs font-medium text-slate-500 bg-slate-100 px-3 py-1.5 rounded-full mr-2 hidden sm:block">
              {stats.totalNights} Nights • {stats.totalStays} Stays
            </div>
            <button onClick={handleExport} className="p-2 text-slate-400 hover:text-indigo-600 hover:bg-indigo-50 rounded-full transition-colors" title="Export Data">
                <Download size={18} />
            </button>
            <button onClick={handleImportClick} className="p-2 text-slate-400 hover:text-indigo-600 hover:bg-indigo-50 rounded-full transition-colors" title="Import Data">
                <Upload size={18} />
            </button>
            <input 
                type="file" 
                ref={fileInputRef} 
                onChange={handleFileChange} 
                className="hidden" 
                accept=".json"
            />
          </div>
        </div>
      </header>

      {/* Main Content */}
      <main className="max-w-3xl mx-auto px-4 py-6">

        {/* Manage View (Formerly Dashboard) */}
        {view === 'dashboard' && (
          <div className="space-y-6">
            <div className="grid grid-cols-3 gap-4">
                <div className="bg-white p-4 rounded-2xl shadow-sm border border-slate-100 text-center">
                    <span className="block text-3xl font-bold text-slate-800">{stats.totalNights}</span>
                    <span className="text-xs text-slate-500 font-medium uppercase tracking-wide">Total Nights</span>
                </div>
                <div className="bg-white p-4 rounded-2xl shadow-sm border border-slate-100 text-center">
                    <span className="block text-3xl font-bold text-indigo-600">{stats.totalStays}</span>
                    <span className="text-xs text-slate-500 font-medium uppercase tracking-wide">Total Stays</span>
                </div>
                <div className="bg-white p-4 rounded-2xl shadow-sm border border-slate-100 text-center">
                    <span className="block text-3xl font-bold text-slate-800 truncate px-1">{stats.topBrand ? stats.topBrand : '-'}</span>
                    <span className="text-xs text-slate-500 font-medium uppercase tracking-wide">Top Loyalty</span>
                </div>
            </div>

            <div className="flex justify-between items-end">
                <h2 className="text-lg font-bold text-slate-800">Recent Activity</h2>
                <button 
                    onClick={() => { setEditingStay(undefined); setIsFormOpen(true); }}
                    className="text-indigo-600 text-sm font-medium hover:bg-indigo-50 px-3 py-1 rounded-lg transition-colors flex items-center gap-1"
                >
                    <Plus size={16} /> Add Stay
                </button>
            </div>

            <div className="space-y-3 pb-20">
                {stays.length === 0 ? (
                     <div className="text-center py-12 bg-white rounded-2xl border-2 border-dashed border-slate-200">
                        <p className="text-slate-400">No stays yet. Start tracking your journey!</p>
                        <button onClick={() => setIsFormOpen(true)} className="mt-4 px-6 py-2 bg-indigo-600 text-white rounded-lg text-sm font-medium">Add First Stay</button>
                    </div>
                ) : (
                    stays.map(stay => {
                        const { dateStr, nights } = formatStayDate(stay.checkInDate, stay.checkOutDate);
                        return (
                            <div key={stay.id} className="bg-white p-4 rounded-xl shadow-sm border border-slate-100 flex justify-between items-center group">
                                <div className="flex items-center gap-4">
                                    <div className="w-12 h-12 rounded-full bg-indigo-50 flex items-center justify-center text-indigo-600 font-bold text-lg shrink-0">
                                        {stay.brand.charAt(0)}
                                    </div>
                                    <div className="min-w-0">
                                        <h3 className="font-semibold text-slate-800 truncate">{stay.hotelName}</h3>
                                        <div className="flex items-center gap-2 text-sm text-slate-500">
                                            <span className="font-medium text-slate-600 shrink-0">{stay.brand}</span>
                                            <span>•</span>
                                            <span className="truncate">{stay.country}</span>
                                        </div>
                                        <div className="flex items-center gap-2 text-xs text-slate-400 mt-0.5">
                                            <span className="shrink-0">{dateStr}</span>
                                            <span className="bg-slate-100 text-slate-600 px-1.5 py-0.5 rounded-full flex items-center gap-0.5">
                                                <Moon size={8} /> {nights}n
                                            </span>
                                        </div>
                                    </div>
                                </div>
                                <div className="flex items-center gap-1 opacity-100 md:opacity-0 group-hover:opacity-100 transition-all">
                                    <button 
                                        onClick={() => handleEditClick(stay)}
                                        className="text-slate-300 hover:text-indigo-600 p-2 transition-colors"
                                        title="Edit"
                                    >
                                        <Pencil size={18} />
                                    </button>
                                    <button 
                                        onClick={() => handleDeleteStay(stay.id)}
                                        className="text-slate-300 hover:text-red-500 p-2 transition-colors"
                                        title="Delete"
                                    >
                                        <Trash2 size={18} />
                                    </button>
                                </div>
                            </div>
                        );
                    })
                )}
            </div>
          </div>
        )}

        {/* Portfolio View */}
        {view === 'portfolio' && (
             <BrandPortfolio stays={stays} />
        )}

        {/* Share View */}
        {view === 'share' && (
            <ShareView stays={stays} summary={stats} />
        )}

      </main>

      {/* Floating Action Button for Mobile Add (Only visible on Manage tab) */}
      {view === 'dashboard' && (
         <button 
            onClick={() => { setEditingStay(undefined); setIsFormOpen(true); }}
            className="md:hidden fixed bottom-24 right-6 bg-indigo-600 text-white p-4 rounded-full shadow-xl hover:bg-indigo-700 transition-transform active:scale-95 z-20"
         >
            <Plus size={24} />
         </button>
      )}

      {/* Bottom Navigation */}
      <nav className="fixed bottom-0 w-full bg-white border-t border-slate-200 py-3 px-6 md:px-0 z-30">
        <div className="max-w-xl mx-auto flex justify-between md:justify-center md:gap-12">
            <NavButton 
                active={view === 'portfolio'} 
                onClick={() => setView('portfolio')} 
                icon={<Briefcase size={24} />} 
                label="Portfolio" 
            />
            <NavButton 
                active={view === 'dashboard'} 
                onClick={() => setView('dashboard')} 
                icon={<LayoutDashboard size={24} />} 
                label="Manage" 
            />
            <NavButton 
                active={view === 'share'} 
                onClick={() => setView('share')} 
                icon={<Share2 size={24} />} 
                label="Share" 
            />
        </div>
      </nav>

      {/* Modals */}
      {isFormOpen && (
        <StayForm 
            initialData={editingStay}
            onSave={handleSaveStay} 
            onClose={handleCloseForm} 
        />
      )}
    </div>
  );
};

const NavButton: React.FC<{ active: boolean; onClick: () => void; icon: React.ReactNode; label: string }> = ({ active, onClick, icon, label }) => (
    <button 
        onClick={onClick}
        className={`flex flex-col items-center gap-1 transition-colors ${active ? 'text-indigo-600' : 'text-slate-400 hover:text-slate-600'}`}
    >
        {icon}
        <span className="text-[10px] font-medium uppercase tracking-wide">{label}</span>
    </button>
);

export default App;

