  id: string;
  hotelName: string;
  brand: string;
  country: string;
  checkInDate: string; // ISO date string YYYY-MM-DD
  checkOutDate: string; // ISO date string YYYY-MM-DD
  notes?: string;
  cost?: number; // Total cost of stay in default currency
  rating?: 'up' | 'down'; // User rating
  createdAt: number;
}

export interface BrandGroup {
  brand: string;
  count: number;
  stays: Stay[];
}

export type ViewMode = 'dashboard' | 'portfolio' | 'share';

export interface StatSummary {
  totalStays: number;
  totalNights: number;
  uniqueBrands: number;
  topBrand: string;
  thisYearStays: number;
}

import { Stay } from '../types';

// Key for localStorage
const STORAGE_KEY = 'stayfolio_data';

// Helper to add days to a date string
const addDays = (dateStr: string, days: number): string => {
  const d = new Date(dateStr);
  d.setDate(d.getDate() + days);
  return d.toISOString().split('T')[0];
};

