                                        <div className="flex items-baseline gap-2">
                                            <h3 className="font-bold text-slate-800 text-sm truncate">{stay.hotelName}</h3>
                                            <span className="text-xs text-slate-400 truncate hidden sm:inline">{stay.brand}</span>
