const StatusTracker: React.FC<{ stays: Stay[] }> = ({ stays }) => {
  const [activeIndex, setActiveIndex] = useState(0);

  const trackerData = useMemo(() => {
    const currentYear = new Date().getFullYear();

    // Map existing stays to programs
    const activePrograms = ELITE_PROGRAMS.map(program => {
        // Calculate nights for this brand in current year
        const brandNights = stays
            .filter(s => s.brand === program.name && new Date(s.checkInDate).getFullYear() === currentYear)
            .reduce((acc, stay) => {
                if (!stay.checkInDate || !stay.checkOutDate) return acc;
                const start = new Date(stay.checkInDate);
                const end = new Date(stay.checkOutDate);
                const nights = Math.round((end.getTime() - start.getTime()) / (1000 * 60 * 60 * 24));
                return acc + Math.max(0, nights);
            }, 0);

        if (brandNights === 0) return null;

        // Determine Status
        // Sort tiers by nights ascending (e.g. 40, then 70) to find next target
        const tiers = [...program.tiers].sort((a, b) => (a.requirements.nights || 0) - (b.requirements.nights || 0));

        let nextTier = null;
        let currentTier = null;

        for (const tier of tiers) {
            const req = tier.requirements.nights || 0;
            if (brandNights >= req) {
                currentTier = tier;
            } else if (!nextTier) {
                nextTier = tier;
            }
        }

        const targetNights = nextTier ? (nextTier.requirements.nights || 0) : (currentTier?.requirements.nights || 0);
        const progress = Math.min(100, (brandNights / targetNights) * 100);
        const isMax = !nextTier;

        return {
            id: program.id,
            brand: program.name,
            nights: brandNights,
            currentTierName: currentTier?.name || 'Member',
            nextTierName: nextTier?.name || 'Max Status',
            targetNights,
            remaining: Math.max(0, targetNights - brandNights),
            progress,
            isMax,
            color: program.color, // e.g. bg-orange-500
            logo: BRAND_LOGOS[program.name]
        };
    }).filter((p): p is NonNullable<typeof p> => p !== null);

    return activePrograms.sort((a, b) => b.nights - a.nights); // Show most progress first
  }, [stays]);

  const handlePrev = () => setActiveIndex(prev => (prev === 0 ? trackerData.length - 1 : prev - 1));
  const handleNext = () => setActiveIndex(prev => (prev === trackerData.length - 1 ? 0 : prev + 1));

  if (trackerData.length === 0) {
      return (
        <div className="relative rounded-3xl overflow-hidden shadow-sm border border-slate-200 bg-white p-6 text-center">
            <div className="bg-slate-100 w-16 h-16 rounded-full flex items-center justify-center mx-auto mb-4 text-slate-400">
