            <p className="text-slate-500 text-sm mb-4">Log a stay at a major hotel chain to unlock status tracking.</p>
        </div>
      );
  }

  const current = trackerData[activeIndex];

  return (
    <div className="relative rounded-3xl overflow-hidden shadow-xl bg-white text-white min-h-[220px] transition-all">
       {/* Dynamic Background */}
       <div className={`absolute inset-0 ${current.color} opacity-90 transition-colors duration-500`}></div>
