       {/* Content */}
       <div className="relative p-6 flex flex-col h-full z-10">
            {/* Header */}
            <div className="flex justify-between items-start mb-4">
                <div className="flex items-center gap-3">
                    <div className="w-10 h-10 bg-white rounded-lg p-1 shadow-sm">
                        <img src={current.logo} alt={current.brand} className="w-full h-full object-contain" onError={(e) => (e.currentTarget.style.display = 'none')} />
                    </div>
                    <div>
                        <p className="text-xs font-bold uppercase tracking-wider opacity-80">Status Tracker 2025</p>
                        <h2 className="text-xl font-black leading-tight">{current.brand}</h2>
                    </div>
                </div>
                <div className="bg-white/20 backdrop-blur-md px-3 py-1 rounded-full border border-white/20">
                    <span className="text-xs font-bold">{current.currentTierName}</span>
                </div>
            </div>

            {/* Main Stats */}
            <div className="flex-1 flex items-end justify-between mb-2">
                <div>
                    <span className="text-5xl font-black tracking-tighter">{current.nights}</span>
                    <span className="text-lg font-medium opacity-80 ml-1">/ {current.targetNights}</span>
                    <p className="text-xs font-bold uppercase tracking-widest opacity-70 mt-1">Qualifying Nights</p>
                </div>
                {!current.isMax && (
                     <div className="text-right pb-1">
                        <span className="text-2xl font-bold">{current.remaining}</span>
                        <p className="text-[10px] font-bold uppercase opacity-80">To {current.nextTierName}</p>
                     </div>
                )}
            </div>

            {/* Progress Bar */}
            <div className="space-y-2">
                <div className="h-3 bg-black/20 rounded-full overflow-hidden backdrop-blur-sm">
                    <div 
                        className="h-full bg-white transition-all duration-1000 ease-out shadow-[0_0_10px_rgba(255,255,255,0.5)]"
                        style={{ width: `${current.progress}%` }}
                    ></div>
                </div>
                {current.isMax && (
                    <div className="flex items-center gap-1.5 text-xs font-bold text-amber-200 justify-center pt-1">
                        <Award size={14} />
                        <span>Top Tier Achieved!</span>
                    </div>
                )}
            </div>

            {/* Navigation Dots/Arrows if multiple */}
            {trackerData.length > 1 && (
                <>
                    <button 
                        onClick={handlePrev}
                        className="absolute left-2 top-1/2 -translate-y-1/2 p-2 rounded-full hover:bg-white/10 transition-colors"
                    >
                        <ChevronLeft size={24} />
                    </button>
                    <button 
                        onClick={handleNext}
                        className="absolute right-2 top-1/2 -translate-y-1/2 p-2 rounded-full hover:bg-white/10 transition-colors"
                    >
                        <ChevronRight size={24} />
                    </button>
                    <div className="absolute bottom-3 left-0 right-0 flex justify-center gap-1.5">
                        {trackerData.map((_, idx) => (
                            <button
                                key={idx}
                                onClick={() => setActiveIndex(idx)}
                                className={`w-1.5 h-1.5 rounded-full transition-all ${idx === activeIndex ? 'bg-white w-3' : 'bg-white/40'}`}
                            />
                        ))}
                    </div>
                </>
            )}
       </div>
    </div>
  );
};

const App: React.FC = () => {
  const [stays, setStays] = useState<Stay[]>([]);
  const [view, setView] = useState<ViewMode>('portfolio'); 
  const [isFormOpen, setIsFormOpen] = useState(false);
  const [editingStay, setEditingStay] = useState<Stay | undefined>(undefined);

  // Filtering States
  const [filterYear, setFilterYear] = useState<string>('All');
  const [filterMonth, setFilterMonth] = useState<string>('All');

  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    setStays(getStays());
  }, []);

  const handleSaveStay = (stayData: Omit<Stay, 'id' | 'createdAt'>) => {
    if (editingStay) {
      const updated = updateStay(editingStay.id, stayData);
      if (updated) {
        setStays(prev => prev.map(s => s.id === updated.id ? updated : s));
      }
    } else {
      const newStay = addStay(stayData);
      setStays(prev => [newStay, ...prev]);
    }
  };

  const handleDeleteStay = (id: string) => {
    deleteStay(id);
    setStays(prev => prev.filter(s => s.id !== id));
  };

  const handleSetRating = (id: string, rating: number) => {
    const updated = updateStay(id, { rating });
    if (updated) {
        setStays(prev => prev.map(s => s.id === updated.id ? updated : s));
    }
  };

  const handleEditClick = (stay: Stay) => {
    setEditingStay(stay);
    setIsFormOpen(true);
  };

  const handleCloseForm = () => {
    setIsFormOpen(false);
    setEditingStay(undefined);
  };

  const handleExport = () => {
    const dataStr = "data:text/json;charset=utf-8," + encodeURIComponent(JSON.stringify(stays));
    const downloadAnchorNode = document.createElement('a');
    downloadAnchorNode.setAttribute("href", dataStr);
    downloadAnchorNode.setAttribute("download", "stayfolio_data.json");
    document.body.appendChild(downloadAnchorNode);
    downloadAnchorNode.click();
    downloadAnchorNode.remove();
  };

  const handleImportClick = () => {
    fileInputRef.current?.click();
  };

  const handleFileChange = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = (e) => {
        try {
          const json = JSON.parse(e.target?.result as string);
          if (Array.isArray(json)) {
             importStays(json);
             setStays(getStays()); // Refresh from storage
             alert('Data imported successfully!');
          }
        } catch (error) {
          alert('Error parsing JSON file');
        }
      };
      reader.readAsText(file);
