                                    {/* Actions */}
                                    <div className="flex items-center gap-1">
                                        <button 
                                            onClick={() => handleEditClick(stay)}
                                            className="p-1.5 text-slate-300 hover:text-indigo-600 hover:bg-indigo-50 rounded-md transition-colors"
                                        >
                                            <Pencil size={14} />
