                            onClick={() => setRating(star)}
                            className="focus:outline-none hover:scale-110 transition-transform"
                        >
                            <Star 
                                size={22} 
                                className={`${rating >= star ? 'fill-amber-400 text-amber-400' : 'text-slate-300'}`} 
