    setCaption(text);
    setLoadingCaption(false);
  };

  const copyToClipboard = () => {
    if (caption) {
      navigator.clipboard.writeText(caption);
      setCopied(true);
      setTimeout(() => setCopied(false), 2000);
    }
  };

  // Calculate stats for the view
  const totalCountries = useMemo(() => {
