        const c = s.country || 'Unknown';
        counts[c] = (counts[c] || 0) + 1;
    });
    return Object.entries(counts)
        .sort((a, b) => b[1] - a[1])
        .slice(0, 3);
  }, [stays]);

  // Calculate top brands (for the list view)
  const topBrands = useMemo(() => {
    const counts: Record<string, number> = {};
