        'Marriott Bonvoy': 'Marriott',
        'IHG One Rewards': 'IHG',
        'Hilton Honors': 'Hilton',
        'Accor Live Limitless': 'Accor'
      };
      if (brandMap[val]) return brandMap[val];
      return val.length > 8 ? val.substring(0, 6) + '..' : val;
  };

