          <div className="flex items-center gap-2">
            <div className="text-xs font-medium text-slate-500 bg-slate-100 px-3 py-1.5 rounded-full mr-2 hidden sm:block">
              {dataLoading ? 'Syncing...' : `${stats.totalNights} Nights • ${stats.totalStays} Stays`}
            </div>

            <button 
                onClick={() => setIsDataModalOpen(true)}
                className="p-2 text-slate-400 hover:text-indigo-600 hover:bg-indigo-50 rounded-full transition-colors" 
                title="Manage Data"
            >
                <Upload size={18} />
            </button>

            <button
                onClick={() => supabase.auth.signOut()}
                className="p-2 text-slate-400 hover:text-rose-600 hover:bg-rose-50 rounded-full transition-colors"
                title="Sign Out"
            >
                <LogOut size={18} />
            </button>
          </div>
        </div>
      </header>

      {/* Main Content */}
      <main className="max-w-3xl mx-auto px-4 py-6">

        {dataLoading && stays.length === 0 ? (
             <div className="py-20 flex justify-center text-slate-300">
                 <Loader2 size={32} className="animate-spin" />
