// --- Supabase Data Methods ---

export const getStays = async (): Promise<Stay[]> => {
  const { data: { user } } = await supabase.auth.getUser();
  if (!user) return [];

  const { data, error } = await supabase
    .from('stays')
    .select('*')
    .order('check_in_date', { ascending: false });

  if (error) {
    console.error('Error fetching stays:', error);
    return [];
  }

  // Map database snake_case columns to application camelCase
  return data.map((item: any) => ({
    id: item.id,
    userId: item.user_id,
    userEmail: item.user_email,
    hotelName: item.hotel_name,
    brand: item.brand,
    country: item.country,
    checkInDate: item.check_in_date,
    checkOutDate: item.check_out_date,
    cost: Number(item.cost),
    rating: item.rating,
    createdAt: new Date(item.created_at).getTime()
  }));
};

// --- Admin: Get User Summary ---
export const getAdminUserSummary = async (): Promise<UserSummary[]> => {
  // Check if admin first (client side check, RLS handles real security)
  const { data: { user } } = await supabase.auth.getUser();
  if (user?.email !== 'jeratomise@gmail.com') return [];

  // Fetch all stays (policy allows admin to see all)
  const { data, error } = await supabase
    .from('stays')
    .select('user_id, user_email, created_at');

  if (error || !data) return [];

  const userMap: Record<string, UserSummary> = {};

  data.forEach((row: any) => {
    if (!row.user_id) return;

    if (!userMap[row.user_id]) {
      userMap[row.user_id] = {
        userId: row.user_id,
        email: row.user_email || 'Unknown',
        totalStays: 0,
        lastActive: row.created_at
      };
    }

    userMap[row.user_id].totalStays++;
    if (new Date(row.created_at) > new Date(userMap[row.user_id].lastActive)) {
      userMap[row.user_id].lastActive = row.created_at;
    }
  });

  return Object.values(userMap);
};

// --- Avatar Management ---
export const uploadUserAvatar = async (file: File): Promise<string | null> => {
    const { data: { user } } = await supabase.auth.getUser();
    if (!user) return null;

    const fileExt = file.name.split('.').pop();
    const fileName = `${user.id}-${Math.random()}.${fileExt}`;
    const filePath = `${fileName}`;

    // 1. Upload to Storage
    const { error: uploadError } = await supabase.storage
        .from('avatars')
        .upload(filePath, file);

    if (uploadError) {
        console.error('Error uploading avatar:', uploadError);
        return null;
    }

    // 2. Get Public URL
    const { data: { publicUrl } } = supabase.storage
        .from('avatars')
        .getPublicUrl(filePath);

    // 3. Update User Metadata
    const { error: updateError } = await supabase.auth.updateUser({
        data: { avatar_url: publicUrl }
    });

    if (updateError) {
        console.error('Error updating user metadata:', updateError);
        return null;
    }

    return publicUrl;
};

export const addStay = async (stay: Omit<Stay, 'id' | 'createdAt' | 'userId' | 'userEmail'>): Promise<Stay | null> => {
  const { data: { user } } = await supabase.auth.getUser();
  if (!user) return null;

  const dbPayload = {
    user_id: user.id,
    user_email: user.email, // Capture email for Admin visibility
    hotel_name: stay.hotelName,
    brand: stay.brand,
    country: stay.country,
    check_in_date: stay.checkInDate,
    check_out_date: stay.checkOutDate,
    cost: stay.cost,
    rating: stay.rating
  };

  const { data, error } = await supabase
    .from('stays')
    .insert([dbPayload])
    .select()
    .single();

  if (error) {
    console.error('Error adding stay:', error);
    return null;
  }

  return {
    id: data.id,
    userId: data.user_id,
    userEmail: data.user_email,
    hotelName: data.hotel_name,
    brand: data.brand,
    country: data.country,
    checkInDate: data.check_in_date,
    checkOutDate: data.check_out_date,
    cost: Number(data.cost),
    rating: data.rating,
    createdAt: new Date(data.created_at).getTime()
  };
};

export const updateStay = async (id: string, updates: Partial<Stay>): Promise<Stay | null> => {
  const { data: { user } } = await supabase.auth.getUser();
  if (!user) return null;

  // Prepare payload based on what's being updated
  const dbPayload: any = {};
  if (updates.hotelName) dbPayload.hotel_name = updates.hotelName;
  if (updates.brand) dbPayload.brand = updates.brand;
  if (updates.country) dbPayload.country = updates.country;
  if (updates.checkInDate) dbPayload.check_in_date = updates.checkInDate;
  if (updates.checkOutDate) dbPayload.check_out_date = updates.checkOutDate;
  if (updates.cost !== undefined) dbPayload.cost = updates.cost;
  if (updates.rating !== undefined) dbPayload.rating = updates.rating;

  const { data, error } = await supabase
    .from('stays')
    .update(dbPayload)
    .eq('id', id)
    .select()
    .single();

  if (error) {
    console.error('Error updating stay:', error);
    return null;
  }

  return {
    id: data.id,
    userId: data.user_id,
    userEmail: data.user_email,
    hotelName: data.hotel_name,
    brand: data.brand,
    country: data.country,
    checkInDate: data.check_in_date,
    checkOutDate: data.check_out_date,
    cost: Number(data.cost),
    rating: data.rating,
    createdAt: new Date(data.created_at).getTime()
  };
};

export const deleteStay = async (id: string): Promise<boolean> => {
  const { error } = await supabase
    .from('stays')
    .delete()
    .eq('id', id);

  if (error) {
    console.error('Error deleting stay:', error);
    return false;
  }
  return true;
};

export const importStays = async (newStays: any[]): Promise<Stay[]> => {
  const { data: { user } } = await supabase.auth.getUser();
  if (!user) return [];

  // Helper to add days if needed (legacy format support)
  const addDays = (dateStr: string, days: number): string => {
    const d = new Date(dateStr);
    d.setDate(d.getDate() + days);
    return d.toISOString().split('T')[0];
  };

  const payload = newStays.map((s: any) => ({
    user_id: user.id,
    user_email: user.email,
    hotel_name: s.hotelName,
    brand: s.brand,
    country: s.country || 'Unknown',
    check_in_date: s.checkInDate || s.date,
    check_out_date: s.checkOutDate || (s.date ? addDays(s.date, 1) : ''),
    cost: s.cost || 0,
    rating: typeof s.rating === 'number' ? s.rating : null
  })).filter(s => s.hotel_name && s.brand && s.check_in_date);

  if (payload.length === 0) return [];

  const { data, error } = await supabase
    .from('stays')
    .insert(payload)
    .select();

  if (error) {
    console.error('Import error:', error);
    return [];
  }

  return data.map((item: any) => ({
    id: item.id,
    userId: item.user_id,
    userEmail: item.user_email,
    hotelName: item.hotel_name,
    brand: item.brand,
    country: item.country,
    checkInDate: item.check_in_date,
    checkOutDate: item.check_out_date,
    cost: Number(item.cost),
    rating: item.rating,
    createdAt: new Date(item.created_at).getTime()
  }));
};

// --- Local Preferences (Status Overrides) ---
// Kept in localStorage as they are device-specific preferences for now

export const getManualStatuses = (): Record<string, string> => {
  try {
    return JSON.parse(localStorage.getItem(STATUS_KEY) || '{}');
  } catch {
    return {};
  }
};

export const saveManualStatus = (programId: string, statusName: string) => {
  const current = getManualStatuses();
  if (statusName === 'Member') {
      delete current[programId];
  } else {
      current[programId] = statusName;
  }
  localStorage.setItem(STATUS_KEY, JSON.stringify(current));
  return current;
};

