         <div className="flex items-center gap-2 text-indigo-600">
            <div className="bg-indigo-600 p-1.5 rounded-lg text-white">
               <ShieldCheck size={20} />
            </div>
            <span className="font-bold text-xl tracking-tight text-slate-900">StayFolio</span>
         </div>
         <button 
            onClick={() => {
                setMode('login');
                window.scrollTo({ top: 0, behavior: 'smooth' });
            }}
            className="text-sm font-bold text-slate-600 hover:text-indigo-600 transition-colors"
         >
            Log In
         </button>
      </nav>

      {/* Hero Section */}
      <div className="max-w-7xl mx-auto px-6 pt-8 pb-20 lg:pt-16 lg:pb-32 grid lg:grid-cols-2 gap-12 lg:gap-24 items-center">

         {/* Left: Copy */}
         <div className="space-y-8">
            <div className="inline-flex items-center gap-2 px-3 py-1 rounded-full bg-indigo-50 border border-indigo-100 text-indigo-600 text-xs font-bold uppercase tracking-wide">
               <Sparkles size={12} />
               <span>New: AI Travel Captioning</span>
            </div>

            <h1 className="text-5xl lg:text-7xl font-black tracking-tight leading-[1.1]">
               The <span className="text-indigo-600">Flighty</span> for your Hotel Stays.
            </h1>

            <p className="text-lg text-slate-500 leading-relaxed max-w-lg">
               StayFolio is the ultimate companion for the elite traveler. Track your history, visualize your footprint, and optimize your status strategy across Marriott, Hyatt, Hilton, and more.
            </p>

            <div className="flex items-center gap-6 text-sm font-medium text-slate-500">
               <div className="flex items-center gap-2">
                  <CheckCircle2 size={18} className="text-emerald-500" />
                  <span>Portfolio Tracking</span>
               </div>
               <div className="flex items-center gap-2">
                  <CheckCircle2 size={18} className="text-emerald-500" />
                  <span>Status Calculator</span>
               </div>
            </div>

            {/* Visual Social Proof */}
            <div className="pt-4 flex items-center gap-4">
                <div className="flex -space-x-3">
                    {[1,2,3,4].map(i => (
                        <div key={i} className="w-10 h-10 rounded-full border-2 border-white bg-slate-200 overflow-hidden">
                             <img src={`https://i.pravatar.cc/100?img=${i + 10}`} alt="User" />
                        </div>
                    ))}
                </div>
                <div>
                    <div className="flex text-amber-400">
                        <Star size={14} fill="currentColor" />
                        <Star size={14} fill="currentColor" />
                        <Star size={14} fill="currentColor" />
                        <Star size={14} fill="currentColor" />
                        <Star size={14} fill="currentColor" />
                    </div>
                    <p className="text-xs text-slate-500 font-bold">Trusted by 2,000+ Travelers</p>
                </div>
