                          <TrendingUp size={24} />
                      </div>
                      <h3 className="text-xl font-bold mb-3">Status Optimization</h3>
                      <p className="text-slate-400 leading-relaxed">
                          We calculate exactly how many nights you need to reach the next tier before the year ends.
                      </p>
