const STATUS_KEY = 'stayfolio_status_overrides';

// --- Supabase Data Methods ---

export const getStays = async (): Promise<Stay[]> => {
  const { data: { user } } = await supabase.auth.getUser();
  if (!user) return [];

  const { data, error } = await supabase
    .from('stays')
    .select('*')
    .order('check_in_date', { ascending: false });

  if (error) {
    console.error('Error fetching stays:', error);
    return [];
  }

  // Map database snake_case columns to application camelCase
  return data.map((item: any) => ({
    id: item.id,
    userId: item.user_id,
    userEmail: item.user_email,
    hotelName: item.hotel_name,
    brand: item.brand,
    country: item.country,
    checkInDate: item.check_in_date,
    checkOutDate: item.check_out_date,
    cost: Number(item.cost),
    rating: item.rating,
    createdAt: new Date(item.created_at).getTime()
  }));
};

// --- Subscription Management ---

export const getUserSubscription = async (userId?: string): Promise<Subscription | null> => {
    // If userId not provided, get current user
    let targetId = userId;
    if (!targetId) {
        const { data: { user } } = await supabase.auth.getUser();
        if (!user) return null;
        targetId = user.id;
    }

    const { data, error } = await supabase
        .from('user_subscriptions')
        .select('*')
        .eq('user_id', targetId)
        .single();

    if (error || !data) {
        // Return default free subscription if no record exists
        return {
            userId: targetId,
            status: 'free',
            expiresAt: null
        };
    }

    return {
        userId: data.user_id,
        status: data.status,
        expiresAt: data.expires_at,
        stripeCustomerId: data.stripe_customer_id
    };
};

export const adminUpdateSubscription = async (userId: string, status: 'free' | 'pro', expiresAt: string | null): Promise<boolean> => {
    const { error } = await supabase
        .from('user_subscriptions')
        .upsert({
            user_id: userId,
            status,
            expires_at: expiresAt,
            updated_at: new Date().toISOString()
        });

    if (error) {
        console.error("Error updating subscription:", error);
        return false;
    }
    return true;
};

// --- App Config (Stripe Toggle) ---

export const getStripeConfig = async (): Promise<boolean> => {
    const { data } = await supabase
        .from('app_config')
        .select('value')
        .eq('key', 'stripe_enabled')
        .single();

    return data?.value === true || data?.value === 'true';
};

export const setStripeConfig = async (enabled: boolean): Promise<boolean> => {
    const { error } = await supabase
        .from('app_config')
        .upsert({
            key: 'stripe_enabled',
