         >
            <Plus size={24} />
         </button>
      )}

      {/* Bottom Navigation */}
      <nav className="fixed bottom-0 w-full bg-white border-t border-slate-200 py-3 px-6 md:px-0 z-30">
        <div className="max-w-xl mx-auto flex justify-between md:justify-center md:gap-6">
            <NavButton 
                active={view === 'portfolio'} 
                onClick={() => setView('portfolio')} 
                icon={<Briefcase size={24} />} 
                label="Portfolio" 
            />
            <NavButton 
                active={view === 'dashboard'} 
                onClick={() => setView('dashboard')} 
                icon={<LayoutDashboard size={24} />} 
                label="Manage" 
            />
            {/* New Concierge Tab (Middle, Highlighted if Pro) */}
            <div className="relative -top-5">
                <button
                    onClick={() => setView('concierge')}
                    className={`p-3 rounded-full shadow-lg border-4 border-slate-50 transition-all ${
                        view === 'concierge' 
                        ? 'bg-indigo-600 text-white' 
                        : 'bg-white text-indigo-600'
                    }`}
                >
                    <Bot size={28} />
                </button>
            </div>
             <NavButton 
                active={view === 'status'} 
                onClick={() => setView('status')} 
                icon={<Crown size={24} />} 
                label="Status" 
            />
            <NavButton 
                active={view === 'share'} 
                onClick={() => setView('share')} 
                icon={<Share2 size={24} />} 
                label="Share" 
            />
        </div>
      </nav>

      {/* Modals */}
      {isFormOpen && (
        <StayForm 
            initialData={editingStay}
            onSave={handleSaveStay} 
            onClose={handleCloseForm} 
        />
      )}

      {isDataModalOpen && (
          <DataManagementModal
            currentStaysCount={stays.length}
            onClose={() => setIsDataModalOpen(false)}
            onImport={handleImportData}
            onExport={handleExport}
          />
      )}
    </div>
  );
};

