  const isPro = useMemo(() => {
      // Admin Override: Forever PRO unless manually simulating free
      if (isAdmin && !adminSimulateFree) {
          return true;
      }

      // Standard Logic
      if (!subscription) return false;
      if (subscription.status === 'pro') {
          if (!subscription.expiresAt) return true; // Lifetime/manual pro
          return new Date() < new Date(subscription.expiresAt);
      }
      return false;
